import strawberry
from strawberry import Schema, Query, Field
from strawberry.schema.types import ModelType
from sqlalchemy import create_engine
from sqlalchemy.orm import sessionmaker

# Define the database models
class Product(ModelType):
    id: int
    name: str
    description: str
    price: float
    reviews: List[Review] = []
    sellers: List[Seller] = []
    categories: List[Category] = []
    images: List[Image] = []

class Review(ModelType):
    id: int
    product_id: int
    rating: float
    text: str
    seller: Seller

class Seller(ModelType):
    id: int
    name: str
    email: str
    products: List[Product] = []

class Category(ModelType):
    id: int
    name: str
    products: List[Product] = []

class Image(ModelType):
    id: int
    product_id: int
    url: str

# Define the GraphQL schema
schema = Schema(query=Query)

@strawberry.type
class Query:
    products: List[Product] = []

    @strawberry.field
    def product(self, id: int):
        return Product.objects.get(id=id)

# Define the SQLAlchemy models
engine = create_engine("sqlite:///products.db")
Session = sessionmaker(bind=engine)
session = Session()

# Create the GraphQL API
app = strawberry.GraphQLRouter(schema)